 13→class VideoLiveWallpaperService : WallpaperService() {
 14→
 15→    internal inner class VideoEngine : Engine() {
 16→        private var mediaPlayer: MediaPlayer? = null
 17→        private var broadcastReceiver: BroadcastReceiver? = null
 18→        private var videoFilePath: String? = null
 19→
 20→        override fun onCreate(surfaceHolder: SurfaceHolder) {
 21→            super.onCreate(surfaceHolder)
 22→
 23→            videoFilePath = try {
 24→                this@VideoLiveWallpaperService.openFileInput("video_live_wallpaper_file_path")
 25→                    .bufferedReader().use { it.readText() }
 26→            } catch (e: Exception) {
 27→                null
 28→            }
 29→
 30→            val intentFilter = IntentFilter(VIDEO_PARAMS_CONTROL_ACTION)
 31→            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
 32→                ContextCompat.registerReceiver(
 33→                    this@VideoLiveWallpaperService,
 34→                    object : BroadcastReceiver() {
 35→                        override fun onReceive(context: Context, intent: Intent) {
 36→                            handleVolumeControl(intent)
 37→                        }
 38→                    }.also { broadcastReceiver = it },
 39→                    intentFilter,
 40→                    ContextCompat.RECEIVER_NOT_EXPORTED
 41→                )
 42→            } else {
 43→                registerReceiver(object : BroadcastReceiver() {
 44→                    override fun onReceive(context: Context, intent: Intent) {
 45→                        handleVolumeControl(intent)
 46→                    }
 47→                }.also { broadcastReceiver = it }, intentFilter)
 48→            }
 49→        }
 50→
 51→        private fun handleVolumeControl(intent: Intent) {
 52→            val shouldMute = intent.getBooleanExtra(KEY_ACTION, false)
 53→            mediaPlayer?.setVolume(
 54→                if (shouldMute) 0f else 1.0f,
 55→                if (shouldMute) 0f else 1.0f
 56→            )
 57→        }
 58→
 59→        override fun onSurfaceCreated(holder: SurfaceHolder) {
 60→            super.onSurfaceCreated(holder)
 61→
 62→            videoFilePath?.let { path ->
 63→                try {
 64→                    mediaPlayer = MediaPlayer().apply {
 65→                        setSurface(holder.surface)
 66→
 67→                        // 支持 Uri 和文件路径
 68→                        if (path.startsWith("content://")) {
 69→                            setDataSource(this@VideoLiveWallpaperService, Uri.parse(path))
 70→                        } else {
 71→                            setDataSource(path)
 72→                        }
 73→
 74→                        isLooping = true
 75→                        setVideoScalingMode(MediaPlayer.VIDEO_SCALING_MODE_SCALE_TO_FIT_WITH_CROPPING)
 76→
 77→                        // 异步准备
 78→                        setOnPreparedListener {
 79→                            it.start()
 80→                        }
 81→                        prepareAsync()
 82→                    }
 83→
 84→                    // 检查静音设置
 85→                    val unmuteFile = File(filesDir, "unmute")
 86→                    val volume = if (unmuteFile.exists()) 1.0f else 0f
 87→                    mediaPlayer?.setVolume(volume, volume)
 88→
 89→                } catch (e: Exception) {
 90→                    e.printStackTrace()
 91→                    mediaPlayer?.release()
 92→                    mediaPlayer = null
 93→                }
 94→            }
 95→        }
 96→
 97→        override fun onVisibilityChanged(visible: Boolean) {
 98→            mediaPlayer?.let {
 99→                if (visible && !it.isPlaying) {
100→                    it.start()
101→                } else if (!visible && it.isPlaying) {
102→                    it.pause()
103→                }
104→            }
105→        }
106→
107→        override fun onSurfaceDestroyed(holder: SurfaceHolder) {
108→            super.onSurfaceDestroyed(holder)
109→            mediaPlayer?.let {
110→                if (it.isPlaying) it.stop()
111→                it.release()
112→            }
113→            mediaPlayer = null
114→        }
115→
116→        override fun onDestroy() {
117→            super.onDestroy()
118→            mediaPlayer?.release()
119→            mediaPlayer = null
120→            broadcastReceiver?.let { unregisterReceiver(it) }
121→        }
122→    }
123→
124→    override fun onCreateEngine(): Engine = VideoEngine()
125→
126→    companion object {
127→        const val VIDEO_PARAMS_CONTROL_ACTION = "com.wallpaper.livewallpaper"
128→        private const val KEY_ACTION = "music"
129→        private const val ACTION_MUSIC_UNMUTE = false
130→        private const val ACTION_MUSIC_MUTE = true
131→
132→        fun muteMusic(context: Context) {
133→            Intent(VIDEO_PARAMS_CONTROL_ACTION).apply {
134→                putExtra(KEY_ACTION, ACTION_MUSIC_MUTE)
135→            }.also { context.sendBroadcast(it) }
136→        }
137→
138→        fun unmuteMusic(context: Context) {
139→            Intent(VIDEO_PARAMS_CONTROL_ACTION).apply {
140→                putExtra(KEY_ACTION, ACTION_MUSIC_UNMUTE)
141→            }.also { context.sendBroadcast(it) }
142→        }
143→
144→        fun setToWallPaper(context: Context) {
145→            Intent(WallpaperManager.ACTION_CHANGE_LIVE_WALLPAPER).apply {
146→                putExtra(
147→                    WallpaperManager.EXTRA_LIVE_WALLPAPER_COMPONENT,
148→                    ComponentName(context, VideoLiveWallpaperService::class.java)
149→                )
150→            }.also {
151→                context.startActivity(it)
152→            }
153→        }
154→    }
155→}
