 27→class FullscreenVideoActivity : ComponentActivity() {
 28→
 29→    override fun onCreate(savedInstanceState: Bundle?) {
 30→        super.onCreate(savedInstanceState)
 31→
 32→        // 设置全屏
 33→        window.apply {
 34→            setFlags(
 35→                WindowManager.LayoutParams.FLAG_FULLSCREEN,
 36→                WindowManager.LayoutParams.FLAG_FULLSCREEN
 37→            )
 38→            decorView.systemUiVisibility = (
 39→                View.SYSTEM_UI_FLAG_LAYOUT_STABLE
 40→                or View.SYSTEM_UI_FLAG_LAYOUT_HIDE_NAVIGATION
 41→                or View.SYSTEM_UI_FLAG_LAYOUT_FULLSCREEN
 42→                or View.SYSTEM_UI_FLAG_HIDE_NAVIGATION
 43→                or View.SYSTEM_UI_FLAG_FULLSCREEN
 44→                or View.SYSTEM_UI_FLAG_IMMERSIVE_STICKY
 45→            )
 46→        }
 47→
 48→        setContent {
 49→            MaterialTheme {
 50→                FullscreenVideoScreen(
 51→                    onDismiss = { finish() }
 52→                )
 53→            }
 54→        }
 55→    }
 56→}
