 58→@Composable
 59→fun FullscreenVideoScreen(onDismiss: () -> Unit) {
 60→    val context = LocalContext.current
 61→    var mediaPlayer by remember { mutableStateOf<MediaPlayer?>(null) }
 62→
 63→    Box(
 64→        modifier = Modifier
 65→            .fillMaxSize()
 66→            .background(Color.Black)
 67→            .clickable(
 68→                interactionSource = remember { MutableInteractionSource() },
 69→                indication = null
 70→            ) {
 71→                onDismiss()
 72→            }
 73→    ) {
 74→        AndroidView(
 75→            factory = { ctx ->
 76→                SurfaceView(ctx).apply {
 77→                    // 确保 SurfaceView 可见
 78→                    setZOrderOnTop(false)
 79→
 80→                    holder.addCallback(object : SurfaceHolder.Callback {
 81→                        override fun surfaceCreated(holder: SurfaceHolder) {
 82→                            try {
 83→                                val videoPath = getVideoPath(ctx)
 84→                                android.util.Log.d("FullscreenVideo", "Video path: $videoPath")
 85→
 86→                                if (videoPath.isNullOrEmpty()) {
 87→                                    android.util.Log.e("FullscreenVideo", "Video path is null or empty")
 88→                                    return
 89→                                }
 90→
 91→                                mediaPlayer = MediaPlayer().apply {
 92→                                    setOnErrorListener { mp, what, extra ->
 93→                                        android.util.Log.e("FullscreenVideo", "MediaPlayer error: what=$what, extra=$extra")
 94→                                        false
 95→                                    }
 96→
 97→                                    setOnInfoListener { mp, what, extra ->
 98→                                        android.util.Log.d("FullscreenVideo", "MediaPlayer info: what=$what, extra=$extra")
 99→                                        false
100→                                    }
101→
102→                                    setSurface(holder.surface)
103→
104→                                    // 支持 Uri 和文件路径
105→                                    if (videoPath.startsWith("content://")) {
106→                                        setDataSource(ctx, Uri.parse(videoPath))
107→                                    } else {
108→                                        setDataSource(videoPath)
109→                                    }
110→
111→                                    isLooping = true
112→                                    setVideoScalingMode(MediaPlayer.VIDEO_SCALING_MODE_SCALE_TO_FIT_WITH_CROPPING)
113→                                    setVolume(0f, 0f) // 静音
114→
115→                                    // 异步准备
116→                                    setOnPreparedListener { mp ->
117→                                        android.util.Log.d("FullscreenVideo", "MediaPlayer prepared, starting playback")
118→                                        mp.start()
119→                                    }
120→
121→                                    android.util.Log.d("FullscreenVideo", "Starting async prepare")
122→                                    prepareAsync()
123→                                }
124→                            } catch (e: Exception) {
125→                                android.util.Log.e("FullscreenVideo", "Error initializing MediaPlayer", e)
126→                                e.printStackTrace()
127→                            }
128→                        }
129→
130→                        override fun surfaceChanged(holder: SurfaceHolder, format: Int, width: Int, height: Int) {
131→                            android.util.Log.d("FullscreenVideo", "Surface changed: ${width}x${height}")
132→                        }
133→
134→                        override fun surfaceDestroyed(holder: SurfaceHolder) {
135→                            android.util.Log.d("FullscreenVideo", "Surface destroyed")
136→                            mediaPlayer?.release()
137→                            mediaPlayer = null
138→                        }
139→                    })
140→                }
141→            },
142→            modifier = Modifier.fillMaxSize()
143→        )
144→    }
145→
146→    DisposableEffect(Unit) {
147→        onDispose {
148→            mediaPlayer?.release()
149→        }
150→    }
151→}
