153→private fun getVideoPath(context: Context): String? {
154→    return try {
155→        val file = File(context.filesDir, "video_live_wallpaper_file_path")
156→        Log.d("FullscreenVideo", "Checking video path file: ${file.absolutePath}")
157→        Log.d("FullscreenVideo", "File exists: ${file.exists()}")
158→
159→        if (file.exists()) {
160→            val path = file.readText().trim()
161→            Log.d("FullscreenVideo", "Read video path: $path")
162→
163→            // 验证路径
164→            if (path.startsWith("content://")) {
165→                Log.d("FullscreenVideo", "Path is a content URI")
166→            } else if (File(path).exists()) {
167→                Log.d("FullscreenVideo", "Path is a valid file path")
168→            } else {
169→                Log.w("FullscreenVideo", "Path does not point to a valid file")
170→            }
171→
172→            path
173→        } else {
174→            Log.e("FullscreenVideo", "Video path file does not exist!")
175→            null
176→        }
177→    } catch (e: Exception) {
178→        Log.e("FullscreenVideo", "Error reading video path", e)
179→        null
180→    }
181→}
