 18→class UnlockWallpaperService : Service() {
 19→
 20→    private val unlockReceiver = object : BroadcastReceiver() {
 21→        override fun onReceive(context: Context, intent: Intent) {
 22→            if (intent.action == Intent.ACTION_USER_PRESENT) {
 23→                // 启动全屏视频 Activity
 24→                val videoIntent = Intent(context, FullscreenVideoActivity::class.java).apply {
 25→                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_HISTORY
 26→                }
 27→                context.startActivity(videoIntent)
 28→            }
 29→        }
 30→    }
 31→
 32→    override fun onCreate() {
 33→        super.onCreate()
 34→
 35→        // 创建通知渠道
 36→        createNotificationChannel()
 37→
 38→        // 启动前台服务
 39→        val notification = createNotification()
 40→        startForeground(NOTIFICATION_ID, notification)
 41→
 42→        // 注册解锁广播接收器
 43→        val filter = IntentFilter(Intent.ACTION_USER_PRESENT)
 44→        registerReceiver(unlockReceiver, filter, RECEIVER_EXPORTED)
 45→    }
 46→
 47→    override fun onDestroy() {
 48→        super.onDestroy()
 49→        try {
 50→            unregisterReceiver(unlockReceiver)
 51→        } catch (e: Exception) {
 52→            e.printStackTrace()
 53→        }
 54→    }
 55→
 56→    override fun onBind(intent: Intent?): IBinder? = null
 57→
 58→    private fun createNotificationChannel() {
 59→        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
 60→            val channel = NotificationChannel(
 61→                CHANNEL_ID,
 62→                "清空桌面服务",
 63→                NotificationManager.IMPORTANCE_LOW
 64→            ).apply {
 65→                description = "保持清空桌面功能运行"
 66→            }
 67→            val notificationManager = getSystemService(NotificationManager::class.java)
 68→            notificationManager.createNotificationChannel(channel)
 69→        }
 70→    }
 71→
 72→    private fun createNotification(): Notification {
 73→        return NotificationCompat.Builder(this, CHANNEL_ID)
 74→            .setContentTitle("清空桌面已启用")
 75→            .setContentText("解锁后自动显示视频壁纸")
 76→            .setSmallIcon(android.R.drawable.ic_menu_view)
 77→            .setPriority(NotificationCompat.PRIORITY_LOW)
 78→            .build()
 79→    }
 80→
 81→    companion object {
 82→        private const val CHANNEL_ID = "clear_desktop_channel"
 83→        private const val NOTIFICATION_ID = 2001
 84→
 85→        fun start(context: Context) {
 86→            val intent = Intent(context, UnlockWallpaperService::class.java)
 87→            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
 88→                context.startForegroundService(intent)
 89→            } else {
 90→                context.startService(intent)
 91→            }
 92→        }
 93→
 94→        fun stop(context: Context) {
 95→            val intent = Intent(context, UnlockWallpaperService::class.java)
 96→            context.stopService(intent)
 97→        }
 98→    }
 99→}
